import React, { useEffect } from 'react';
import "aos/dist/aos.css";
import AOS from "aos";

const Contact = () => {

    useEffect(() => {
        AOS.init({ duration: 1000, easing: "ease-in-out", once: true });
      }, []);

    return (
        <section id="contact" class="contact section">
            <div class="container section-title aos-init aos-animate" data-aos="fade-up">
                <h2>Contact</h2>
                <p>Necessitatibus eius consequatur ex aliquid fuga eum quidem sint consectetur velit</p>
            </div>

            <div class="container aos-init aos-animate d-flex justify-content-center" data-aos="fade" data-aos-delay="100">
                    <div class="col-lg-10">
                        <form action="forms/contact.php" method="post" class="php-email-form aos-init aos-animate" data-aos="fade-up" data-aos-delay="200">
                            <div class="row gy-4">

                                <div class="col-md-6">
                                    <input type="text" name="name" class="form-control" placeholder="Your Name" required="" />
                                </div>

                                <div class="col-md-6 ">
                                    <input type="email" class="form-control" name="email" placeholder="Your Email" required="" />
                                </div>

                                <div class="col-md-12">
                                    <input type="text" class="form-control" name="subject" placeholder="Subject" required="" />
                                </div>

                                <div class="col-md-12">
                                    <textarea class="form-control" name="message" rows="6" placeholder="Message" required="" />
                                </div>

                                <div class="col-md-12 text-center">
                                    <div class="loading">Loading</div>
                                    <div class="error-message"></div>
                                    <div class="sent-message">Your message has been sent. Thank you!</div>

                                    <button type="submit">Send Message</button>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
        </section>
    );
};

export default Contact;
